import boto3
import json
import uuid

def publish_user_data_to_sqs(queue_url: str, user_data: dict) -> dict:
    """
    Publishes user data, including PII, as a JSON message to an SQS queue.

    Args:
        queue_url (str): The URL of the SQS queue.
        user_data (dict): A dictionary containing user data,
                          e.g., {'email': 'test@example.com', 'phone': '+15551234567', 'address': '123 Main St'}.

    Returns:
        dict: The response from the SQS send_message API call, or an error dictionary.
    """
    sqs_client = boto3.client('sqs')

    try:
        # Ensure user_data is JSON serializable
        message_body = json.dumps(user_data)

        response = sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body,
            # Optionally add a MessageDeduplicationId for FIFO queues
            # MessageDeduplicationId=str(uuid.uuid4()),
            # Optionally add a MessageGroupId for FIFO queues
            # MessageGroupId='UserRegistration'
        )
        print(f"Message published successfully. MessageId: {response.get('MessageId')}")
        return response
    except Exception as e:
        print(f"Error publishing message to SQS: {e}")
        return {"error": str(e)}

